import { ApiError, apiRequest } from '@reeve/shared';
export async function postDetect(file) {
    const form = new FormData();
    form.append('file', file);
    return apiRequest('/detect', { method: 'POST', body: form });
}
export async function postIdentify(file, bbox) {
    const form = new FormData();
    form.append('file', file);
    if (bbox)
        form.append('bbox', bbox.join(','));
    return apiRequest('/identify', { method: 'POST', body: form });
}
export function extractErrorMessage(err) {
    if (err instanceof ApiError) {
        const body = err.body;
        if (body && typeof body === 'object' && 'detail' in body && typeof body.detail === 'string') {
            return body.detail;
        }
        if (typeof body === 'string' && body.trim())
            return body;
        return `HTTP ${err.status}`;
    }
    if (err instanceof Error)
        return err.message;
    return String(err);
}
